// 1. Pega o texto gerado pela IA
let textoCru = $input.first().json.output || "";

// 2. Tira formatações de markdown que a IA insiste em colocar
textoCru = textoCru.replace(/```json/gi, '').replace(/```/g, '').trim();

// 3. Extrator Cirúrgico: Pega só o que está entre { e } ignorando textos como "Aqui está sua resposta:"
let inicioJson = textoCru.indexOf('{');
let fimJson = textoCru.lastIndexOf('}');

if (inicioJson !== -1 && fimJson !== -1) {
    textoCru = textoCru.substring(inicioJson, fimJson + 1);
}

let objetoJson;

try {
    // 4. Tenta ler o JSON limpo
    objetoJson = JSON.parse(textoCru);
} catch (erro) {
    // 5. MODO DE SEGURANÇA MÁXIMA: 
    // Se a IA desobedeceu totalmente, nós dividimos o texto nas 4 caixinhas do Lovable para não dar erro na tela.
    objetoJson = { 
        "resposta_chat": "A IA respondeu em formato de texto livre. Aqui está a análise: \n\n" + textoCru,
        "anomalia": "Dados não estruturados pela IA.",
        "insight": "Dados não estruturados pela IA.",
        "monitorando": "Acompanhando portais de transparência."
    };
}

// 6. Entrega as 4 chaves lidas ou salvas pelo modo de segurança
return [{ json: objetoJson }];

// 1. Puxa o arquivo fatiado da memória
const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const csvText = binaryBuffer.toString('utf-8');

// 2. A Lista de Ouro (Agora apontando para a DIA_PROPOSTA)
const colunasDesejadas = [
    'DIA_PROPOSTA', 
    'VALOR_REPASSE_PROPOSTA_EMENDA',
    'NM_PROPONENTE',         
    'MUNIC_PROPONENTE',
    'OBJETO_PROPOSTA',
    'Partido',
    'NomeBloco',
    'TipoParlamentar',
    'DESC_ORGAO_SUP',
    'NATUREZA_JURIDICA'
];

const lines = csvText.split('\n');
if (lines.length === 0) return [];

function parseCSVLine(text) {
    let ret = [], keep = false, token = '';
    for (let i = 0; i < text.length; i++) {
        let c = text[i];
        if (c === '"') keep = !keep;
        else if (c === ',' && !keep) { ret.push(token.trim().replace(/^"|"$/g, '')); token = ''; }
        else token += c;
    }
    ret.push(token.trim().replace(/^"|"$/g, ''));
    return ret;
}

const header = parseCSVLine(lines[0]);
const indexMap = {};
colunasDesejadas.forEach(col => {
    indexMap[col] = header.findIndex(h => h === col);
});

const results = [];

// 3. Varre as linhas extraindo o filé mignon
for (let i = 1; i < lines.length; i++) {
    if (!lines[i] || lines[i].trim() === '') continue;

    let cols = parseCSVLine(lines[i]);
    let rowObject = {};

    colunasDesejadas.forEach(col => {
        let idx = indexMap[col];
        let val = (idx !== -1 && cols[idx]) ? cols[idx] : null;

        if (col === 'VALOR_REPASSE_PROPOSTA_EMENDA') {
            if (val) {
                let valorLimpo = val.replace(/\./g, '').replace(',', '.');
                rowObject['VALOR_LIMPO'] = Number(valorLimpo) || 0;
            } else {
                rowObject['VALOR_LIMPO'] = 0;
            }
        } else if (col === 'DIA_PROPOSTA') {
            // 🔥 A MÁGICA DO ANO: Lê a data (ex: 12/04/2010) e extrai só o "2010"
            let ano = 'Não Informado';
            if (val && val.trim() !== '') {
                let match = val.match(/\b(19|20)\d{2}\b/);
                ano = match ? match[0] : val;
            }
            rowObject['ANO'] = ano;
            rowObject['DIA_PROPOSTA'] = (val && val.trim() !== '') ? val : 'Não Informado';
        } else {
            rowObject[col] = (val && val.trim() !== '') ? val : 'Não Informado';
        }
    });

    results.push({ json: rowObject });
}

return results;
